const contracts = $input.first().json || [];
const contractArray = Array.isArray(contracts) ? contracts : [contracts];

if (contractArray.length === 0) {
  return [{ json: { has_expiring: false, count: 0, message: 'No contracts expiring in next 90 days' } }];
}

const summary = contractArray.map(c => {
  const daysUntil = Math.ceil((new Date(c.expiration_date) - Date.now()) / 86400000);
  const autoRenew = c.auto_renewal?.enabled ? '🔄 Auto-renews' : '⏰ Expires';
  return `• *${c.file_name}* — ${autoRenew} in ${daysUntil} days (${c.expiration_date}) | Dept: ${c.department}`;
}).join('\n');

return [{
  json: {
    has_expiring: true,
    count: contractArray.length,
    summary,
    contracts: contractArray
  }
}];

